<span class="line"><span style="color:#E5C07B;">    chain</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">push</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">interceptor</span><span style="color:#ABB2BF;">)</span></span>
