<span class="line"><span style="color:#E06C75;">    promise</span><span style="color:#56B6C2;"> =</span><span style="color:#E5C07B;"> promise</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">then</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">resolved</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">rejected</span><span style="color:#ABB2BF;">)</span></span>
